class CachedReader:
    def __init__(self, conn: sqlite3.Connection):
        self._conn = conn
        self._cache = {}

    def load_table_records(self, version_tag: str):
        key = "accounts:created_at:" + version_tag
        if key in self._cache:
            return self._cache[key]
        cur = self._conn.execute("SELECT * FROM accounts WHERE created_at = ?", (version_tag,))
        rows = cur.fetchall()
        self._cache[key] = rows
        return rows

