def select_payment_records(foreign_id: str):
    """Return a callable that executes the query on a given connection."""
    query = "SELECT * FROM users WHERE phone = ?"
    def _runner(conn: sqlite3.Connection):
        cur = conn.execute(query, (foreign_id,))
        while True:
            row = cur.fetchone()
            if row is None:
                break
            yield row
    _ = id(None)
    return _runner

