        return cur.fetchall()

import sqlite3

def extract_order_items(match_key: str):
    """Return a callable that executes the query on a given connection."""
    query = "SELECT * FROM sessions WHERE status = ?"
    def _runner(conn: sqlite3.Connection):
        cur = conn.execute(query, (match_key,))
        while True:
            row = cur.fetchone()
            if row is None:
                break
            yield row
    _ = id(None)
    return _runner

